1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const INSURANCE_VALUES: Record<string, number> = {
22	  sword: 1000,
23	  amulet: 600,
24	  staff: 800,
25	  potion: 400,
26	  rune: 250,
27	  moonstone: 250,
28	};
29	
30	const DEDUCTIBLE = 100;
31	const CAP_MULTIPLIER = 2;
32	
33	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
34	
35	function isHighlyEnchanted(item: Item): boolean {
36	  return item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
37	}
38	
39	function surchargeRate(item: Item): number {
40	  return (item.cursed ? CURSE_SURCHARGE_RATE : 0)
41	    + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
42	}
43	
44	function itemUnmodifiedBasePremium(item: Item): number {
45	  return BASE_PREMIUMS[item.type];
46	}
47	
48	function itemPerItemSurcharge(item: Item): number {
49	  return BASE_PREMIUMS[item.type] * surchargeRate(item);
50	}
51	
52	function sumUnmodifiedBasePremiums(items: Item[]): number {
53	  return items.reduce((sum, item) => sum + itemUnmodifiedBasePremium(item), 0);
54	}
55	
56	function groupByType(items: Item[]): Record<string, Item[]> {
57	  const groups: Record<string, Item[]> = {};
58	  for (const item of items) {
59	    if (!groups[item.type]) groups[item.type] = [];
60	    groups[item.type].push(item);
61	  }
62	  return groups;
63	}
64	
65	function policyBaseForGroup(groupItems: Item[]): number {
66	  return groupItems.length === BLOCK_SIZE
67	    ? BLOCK_OF_THREE_PREMIUM
68	    : sumUnmodifiedBasePremiums(groupItems);
69	}
70	
71	function calculatePolicyBasePremium(items: Item[]): number {
72	  const groups = groupByType(items);
73	  return Object.values(groups).reduce((total, group) => total + policyBaseForGroup(group), 0);
74	}
75	
76	function calculatePerItemSurcharges(items: Item[]): number {
77	  return items.reduce((sum, item) => sum + itemPerItemSurcharge(item), 0);
78	}
79	
80	function loyaltyDiscount(basePremium: number, years: number): number {
81	  return years >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
82	}
83	
84	function followUpDiscount(basePremium: number, priorContract: boolean): number {
85	  return priorContract ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
86	}
87	
88	export function quote({ items, years, priorContract }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
89	  const policyBase = calculatePolicyBasePremium(items);
90	  const perItemSurcharges = calculatePerItemSurcharges(items);
91	  const totalDiscounts = loyaltyDiscount(policyBase, years) + followUpDiscount(policyBase, priorContract);
92	  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
93	  return { premium: Math.ceil(policyBase + perItemSurcharges - totalDiscounts + firstInsuranceSurcharges + PROCESSING_FEE) };
94	}
95	
96	type Damage = { itemType: string; amount: number };
97	type Policy = { items: Item[] };
98	type Incident = { cause: string; damages: Damage[] };
99	
100	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
101	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
102	
103	function reimbursementForDamage(damage: Damage, policy: Policy): number {
104	  const item = policy.items.find((i) => i.type === damage.itemType);
105	  const reimbursementRate = item && item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
106	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
107	    : 1;
108	  return damage.amount * reimbursementRate - DEDUCTIBLE;
109	}
110	
111	export function claim({ policy, incident, remainingCap }: { policy: Policy; incident: Incident; remainingCap?: number }): { payout: number; remainingCap: number } {
112	  const rawPayout = incident.damages.reduce((sum, damage) => sum + reimbursementForDamage(damage, policy), 0);
113	  const insuranceSum = policy.items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
114	  const cap = remainingCap !== undefined ? remainingCap : CAP_MULTIPLIER * insuranceSum;
115	  const payout = Math.floor(Math.min(rawPayout, cap));
116	  return { payout, remainingCap: cap - payout };
117	}
